using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class BacklogTraining : TrainingContentBase
{
    public BacklogTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Backlog Overview",
            Slug = "backlog-overview",
            Summary = "What the backlog is, how it relates to the kanban board, filtering jobs, view modes, and creating new jobs.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/backlog"]""",
            Tags = """["backlog","jobs","kanban"]""",
            ContentJson = """{"body":"## Backlog Overview\n\nThe Backlog is your master list of all jobs across every track type. While the Kanban Board gives you a visual, stage-by-stage view of a single track, the Backlog lets you see every job in the system at once — search, filter, sort, and triage work before it hits the board.\n\n### Backlog vs. Kanban Board\n\nThe Kanban Board shows jobs organized into columns by stage within a single track type (e.g., Production, R&D/Tooling, Maintenance). You interact with jobs visually — dragging cards between stages, seeing WIP limits, and tracking flow.\n\nThe Backlog is a flat list of all jobs regardless of track type. It is the place to:\n- **Find any job** by number, title, customer, or assignee\n- **Triage incoming work** — review unassigned or low-priority jobs\n- **Bulk review** — scan across tracks to spot overdue items, unbalanced workloads, or stalled jobs\n- **Create new jobs** that land on the board in their track's first stage\n\nEvery job in the Backlog also appears on its corresponding Kanban Board. Changes made in either place are reflected in both.\n\n### Two View Modes\n\nThe Backlog offers two ways to look at your jobs:\n\n**Table View (default)** — A data table with sortable, filterable columns: Job Number, Title, Stage, Priority, Assignee, Customer, and Due Date. Click any column header to sort. Use the column filter icons for per-column filtering (text search, enum selection, or date range). Click any row to open the full job detail dialog.\n\n**Card View** — A grid of job cards showing the job number, title, stage chip (color-coded), priority dot, assignee avatar, customer name, and due date. Cards with active holds show an 'On Hold' badge. Overdue cards are visually highlighted. Click any card to open the job detail dialog.\n\nToggle between views using the view icons in the page header (view_list for table, view_module for cards). Your preference is saved and restored on your next visit.\n\n### Filtering\n\nFour filters in the page header narrow down the list:\n\n- **Search** — free-text search across job number and title. Results update as you type.\n- **Track Type** — filter to a specific track (Production, R&D/Tooling, etc.). Shows only jobs whose current stage belongs to that track.\n- **Priority** — filter by Low, Normal, High, or Urgent.\n- **Assignee** — filter to jobs assigned to a specific team member.\n\nAll filters work together (AND logic). The filtered count is reflected in both table and card views.\n\n### Creating Jobs\n\nClick the 'Create Job' button (with the + icon) in the page header to open the job creation dialog. You will enter:\n\n- **Title** (required, max 200 characters)\n- **Description** (optional, multi-line)\n- **Track Type** (required) — determines which board and initial stage the job enters\n- **Customer** (optional) — links the job to a customer record\n- **Assignee** (optional) — assigns a team member. If the selected user has an incomplete profile, a warning is shown.\n- **Priority** (defaults to Normal) — Low, Normal, High, or Urgent\n- **Due Date** (optional) — displayed in red when overdue\n\nThe new job is placed in the first stage of the selected track type and appears on both the Backlog and the Kanban Board immediately.\n\n### Job Detail\n\nClicking any row (table view) or card (card view) opens the full job detail dialog via the DetailDialogService. The URL updates to include `?detail=job:{id}`, making the link shareable and bookmarkable. From the detail dialog you can edit the job, view subtasks, files, activity log, and more.\n\n### Row Styling (Table View)\n\n- **Overdue rows** get the `row--overdue` class — a subtle red tint indicating the due date has passed.\n- **Selected row** gets the `row--selected` class — highlighted to show which job's detail is currently open.\n- **Stage color tint** — each row has a faint background tint matching its stage color via the `--row-tint` CSS custom property.\n\n### Priority Colors\n\nPriority is shown as a colored dot next to the priority name:\n- **Low** — slate gray (#94a3b8)\n- **Normal** — teal (#0d9488)\n- **High** — amber (#f59e0b)\n- **Urgent** — red (#dc2626)","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Backlog — Guided Tour",
            Slug = "backlog-walkthrough",
            Summary = "A guided tour of the backlog page: search, filters, table view, card view toggle, creating jobs, and opening job details.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/backlog"]""",
            Tags = """["backlog","walkthrough"]""",
            ContentJson = """{"appRoute":"/backlog","startButtonLabel":"Tour Backlog","steps":[{"element":".page-header app-input","popover":{"title":"Search Jobs","description":"Type here to search by job number or title. Results filter in real time as you type. Works in both table and card view.","side":"bottom"}},{"element":".page-header app-select:nth-of-type(1)","popover":{"title":"Track Type Filter","description":"Filter jobs by track type (e.g., Production, R&D/Tooling, Maintenance). When selected, only jobs whose current stage belongs to that track are shown. Set to 'All Tracks' to see everything.","side":"bottom"}},{"element":".page-header app-select:nth-of-type(2)","popover":{"title":"Priority Filter","description":"Filter by priority level: Low, Normal, High, or Urgent. Set to 'All Priorities' to show all jobs regardless of priority.","side":"bottom"}},{"element":".page-header app-select:nth-of-type(3)","popover":{"title":"Assignee Filter","description":"Filter to jobs assigned to a specific team member. The dropdown lists all users. Set to 'All Assignees' to remove the filter.","side":"bottom"}},{"element":".view-toggle","popover":{"title":"View Mode Toggle","description":"Switch between Table view (view_list icon) and Card view (view_module icon). Table view shows a sortable, filterable data table. Card view shows a grid of job cards with stage colors, priority dots, and assignee avatars. Your preference is saved automatically.","side":"bottom"}},{"element":".new-job-btn","popover":{"title":"Create Job","description":"Click to open the job creation dialog. You'll fill in a title (required), optional description, track type (required — determines which board the job enters), customer, assignee, priority, and due date. The job is created in the first stage of the selected track.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Jobs Table","description":"The main data table showing all filtered jobs. Columns: Job Number (80px), Title, Stage (color-coded chip), Priority (colored dot + label), Assignee (avatar), Customer, and Due Date. Click any column header to sort. Click the filter icon on filterable columns (Stage, Priority, Assignee, Customer, Due Date) for per-column filtering. Click any row to open the full job detail dialog.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Backlog Field Reference",
            Slug = "backlog-field-reference",
            Summary = "Complete reference for every field, column, filter, button, validation rule, row style, and view mode in the Backlog.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/backlog"]""",
            Tags = """["backlog","reference"]""",
            ContentJson = """{"title":"Backlog Field Reference","groups":[{"heading":"Page Header Filters","items":[{"label":"Search","value":"Free-text input. Filters jobs by title or job number. Case-insensitive, matches anywhere in the string. Results update in real time as you type."},{"label":"Track Type","value":"Select dropdown. Options: 'All Tracks' (default, shows all jobs) plus one option per configured track type (e.g., Production, R&D/Tooling, Maintenance). Filters by matching the job's current stage to the selected track's stage list."},{"label":"Priority","value":"Select dropdown. Options: 'All Priorities' (default), Low, Normal, High, Urgent. Filters to jobs matching the selected priority level."},{"label":"Assignee","value":"Select dropdown. Options: 'All Assignees' (default) plus one option per user (shown by name). Filters to jobs assigned to the selected user (matched by initials)."}]},{"heading":"View Mode Toggle","items":[{"label":"Table View button (view_list icon)","value":"Switches to the data table view. Active state shown by icon-btn--active class. This is the default view mode."},{"label":"Card View button (view_module icon)","value":"Switches to the card grid view. Active state shown by icon-btn--active class."},{"label":"View preference persistence","value":"View mode is saved to user preferences (key: backlog:viewMode) and synced to the URL via ?view=card query param. Table is the default — only card mode adds a query param. Preference is restored on next visit unless the URL explicitly specifies a view."}]},{"heading":"Job Create/Edit Dialog Fields","items":[{"label":"Title (required)","value":"Text input, max 200 characters. Validators: required, maxLength(200). data-testid: job-title. Shown on kanban cards, backlog table, and detail views."},{"label":"Description","value":"Textarea, 3 rows. Optional, no max length enforced in UI. data-testid: job-description. Provides additional context about the job scope."},{"label":"Track Type (create mode only)","value":"Select dropdown, required. Options loaded from API (configured track types). Validators: required. data-testid: job-track-type. Determines which kanban board and initial stage the job enters. Hidden in edit mode — track type cannot be changed after creation."},{"label":"Customer","value":"Select dropdown, optional. Options loaded from API (customer list) plus a null/'-- None --' option. data-testid: job-customer. Links job to a customer record."},{"label":"Assignee","value":"Select dropdown, optional. Options loaded from API (user list) plus a null/'-- None --' option. data-testid: job-assignee. If the selected user has an incomplete profile (missing required onboarding fields), a warning message is displayed below the field."},{"label":"Priority","value":"Select dropdown. Options: Low, Normal, High, Urgent. Default: Normal. data-testid: job-priority. Controls the priority dot color in table and card views."},{"label":"Due Date","value":"Datepicker, optional. data-testid: job-due-date. When set and the date has passed, the job is flagged as overdue (red text in table, highlighted card in grid)."},{"label":"Save button","value":"data-testid: job-save-btn. Disabled when form is invalid or saving is in progress. Hover shows a validation popover listing violations (e.g., 'Title is required', 'Track Type is required')."},{"label":"Cancel button","value":"Closes the dialog without saving. No confirmation unless the form has unsaved changes (dirty form guard)."}]},{"heading":"Table Columns","items":[{"label":"Job Number","value":"Width: 80px. Sortable, filterable (text). Rendered in monospace-styled span with class 'job-number'. Shows the auto-generated job number (e.g., J-1001)."},{"label":"Title","value":"Sortable, filterable (text). Rendered with class 'job-title'. The primary job name."},{"label":"Stage","value":"Width: 100px. Sortable, filterable (enum — options derived from current job data). Rendered as a colored chip with --chip-color set to the stage's configured color."},{"label":"Priority","value":"Width: 90px. Sortable, filterable (enum — Low/Normal/High/Urgent). Rendered as a colored dot (background color from PRIORITY_COLORS) followed by the priority name text."},{"label":"Assignee","value":"Width: 60px, center-aligned. Filterable (enum — options from user list by initials/name). Rendered as an app-avatar component (sm size) with the user's initials and color. Unassigned shows an em dash (—)."},{"label":"Customer Name","value":"Width: 120px. Sortable, filterable (enum — options derived from current job data, duplicates removed). Plain text, em dash (—) when no customer assigned."},{"label":"Due Date","value":"Width: 100px. Sortable, filterable (date). Formatted as MM/dd/yyyy via Angular DatePipe. Overdue dates rendered with class 'overdue-text' (red color)."}]},{"heading":"Row Styling (Table View)","items":[{"label":"row--overdue","value":"Applied when job.isOverdue is true (due date has passed). Adds a subtle red background tint to the entire row."},{"label":"row--selected","value":"Applied when the job's ID matches the currently selected job (detail dialog is open for this job). Highlights the row to indicate selection."},{"label":"--row-tint CSS variable","value":"Set to the job's stage color. Provides a faint background tint matching the stage color, giving a visual cue about which stage each job is in."}]},{"heading":"Card View Elements","items":[{"label":"Job Number","value":"Displayed in the card header with class 'backlog-card__number'."},{"label":"On Hold badge","value":"Warning chip shown in the card header when job.activeHolds.length > 0. Text: 'On Hold'."},{"label":"Title","value":"Card body text with class 'backlog-card__title'."},{"label":"Stage chip","value":"Color-coded chip with --chip-color set to job.stageColor. Shows the current stage name."},{"label":"Priority dot + name","value":"Colored dot (backlog-card__priority-dot) with background from PRIORITY_COLORS, followed by priority name text."},{"label":"Assignee avatar","value":"app-avatar (sm size) shown when job has an assignee. Omitted when unassigned."},{"label":"Customer","value":"Shown below the meta area with a business icon. Only rendered when job.customerName is present."},{"label":"Due Date","value":"Shown in the card footer with an event icon. Formatted as short date. Class 'backlog-card__date--overdue' applied when overdue (red). 'No date' text shown when no due date set."},{"label":"backlog-card--overdue","value":"Applied to the entire card when job.isOverdue is true. Visually highlights the card."},{"label":"backlog-card--selected","value":"Applied when this card's job ID matches the selected job. Highlights the card border/background."}]},{"heading":"Buttons and Actions","items":[{"label":"Create Job (page header)","value":"Button with + icon and text. Class: new-job-btn. Opens the job creation dialog in 'create' mode. No data-testid on this button (it's in the page header, not a dialog)."},{"label":"Row click (table)","value":"Clicking any table row opens the job detail dialog via DetailDialogService. URL updates to ?detail=job:{id}. The selected row gets row--selected styling."},{"label":"Card click (card view)","value":"Clicking any card opens the job detail dialog via DetailDialogService. URL updates to ?detail=job:{id}. The selected card gets backlog-card--selected styling."},{"label":"Detail dialog URL auto-open","value":"On page load, if the URL contains ?detail=job:{id}, the job detail dialog opens automatically. This supports direct links, bookmarks, and browser back/forward."}]},{"heading":"Data Loading","items":[{"label":"Initial load","value":"Uses LoadingService.track() with forkJoin to load jobs, track types, and users simultaneously. Global loading overlay shown with message 'Loading backlog...'."},{"label":"Refresh after save","value":"After creating or editing a job via the dialog, the job list is reloaded from the API. The dialog closes and the updated data appears."},{"label":"Error state","value":"If the initial load fails, the page shows an error icon (error_outline) with a failure message instead of the table/card content."}]},{"heading":"Priority Colors","items":[{"label":"Low","value":"#94a3b8 (slate gray)"},{"label":"Normal","value":"#0d9488 (teal)"},{"label":"High","value":"#f59e0b (amber)"},{"label":"Urgent","value":"#dc2626 (red)"}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Backlog Knowledge Check",
            Slug = "backlog-quiz",
            Summary = "Test your knowledge of the Backlog module: filters, view modes, job creation, table columns, and card elements.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/training"]""",
            Tags = """["backlog","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"bl1","text":"What is the primary purpose of the Backlog page compared to the Kanban Board?","options":[{"id":"a","text":"The Backlog replaces the Kanban Board for teams that prefer list views"},{"id":"b","text":"The Backlog shows all jobs across every track type in a flat list for searching, filtering, and triaging work","isCorrect":true},{"id":"c","text":"The Backlog only shows jobs that haven't been assigned to a track yet"},{"id":"d","text":"The Backlog is a historical archive of completed jobs"}],"explanation":"The Backlog is a master list of all jobs across every track type. While the Kanban Board shows one track at a time organized by stage columns, the Backlog lets you see, search, and filter all jobs regardless of which track they belong to."},{"id":"bl2","text":"You want to find all urgent jobs assigned to a specific team member. What filters do you set?","options":[{"id":"a","text":"Set the Search field to the team member's name and the Priority filter to Urgent"},{"id":"b","text":"Set the Assignee filter to the team member and the Priority filter to Urgent","isCorrect":true},{"id":"c","text":"Set the Track Type filter and then sort the Priority column descending"},{"id":"d","text":"Use the Search field to type 'urgent' and scan the results visually"}],"explanation":"The Backlog has dedicated Assignee and Priority filters in the page header. Set Assignee to the team member's name and Priority to Urgent. These filters work together with AND logic, showing only jobs matching both criteria."},{"id":"bl3","text":"What happens when you switch from Table view to Card view?","options":[{"id":"a","text":"The URL updates to include ?view=card and the preference is saved for your next visit","isCorrect":true},{"id":"b","text":"Only the display changes — no URL or preference update occurs"},{"id":"c","text":"You are navigated to a completely different route (/backlog/cards)"},{"id":"d","text":"The card view opens in a new browser tab"}],"explanation":"The view mode is synced to the URL via the ?view=card query parameter and saved to user preferences (key: backlog:viewMode). Table view is the default and doesn't add a query param. Your choice persists across sessions."},{"id":"bl4","text":"In the job creation dialog, which fields are required?","options":[{"id":"a","text":"Title, Description, and Track Type"},{"id":"b","text":"Title and Track Type","isCorrect":true},{"id":"c","text":"Title, Track Type, Priority, and Customer"},{"id":"d","text":"Only Title is required — Track Type is auto-selected"}],"explanation":"The job creation dialog requires Title (max 200 characters) and Track Type. All other fields — Description, Customer, Assignee, Priority, and Due Date — are optional. Priority defaults to Normal if not changed."},{"id":"bl5","text":"What data-testid attribute identifies the job title input field in the create/edit dialog?","options":[{"id":"a","text":"data-testid=\"backlog-title\""},{"id":"b","text":"data-testid=\"job-title\"","isCorrect":true},{"id":"c","text":"data-testid=\"create-job-title\""},{"id":"d","text":"data-testid=\"title-input\""}],"explanation":"The job title input has data-testid=\"job-title\". All job dialog fields follow the pattern data-testid=\"job-{field}\": job-title, job-description, job-track-type, job-customer, job-assignee, job-priority, job-due-date, and job-save-btn."},{"id":"bl6","text":"A job row in the table has a red background tint. What does this indicate?","options":[{"id":"a","text":"The job has a critical priority level"},{"id":"b","text":"The job has an error and needs attention"},{"id":"c","text":"The job's due date has passed — it is overdue","isCorrect":true},{"id":"d","text":"The job is currently on hold"}],"explanation":"The row--overdue class is applied when job.isOverdue is true (the due date has passed). This adds a subtle red background tint to the entire row. Note: the faint stage color tint (--row-tint) is separate and always present."},{"id":"bl7","text":"What does the --row-tint CSS custom property control in the backlog table?","options":[{"id":"a","text":"It sets the text color of the job title to match the priority"},{"id":"b","text":"It provides a faint background tint matching the job's current stage color","isCorrect":true},{"id":"c","text":"It controls the border color on the left side of each row"},{"id":"d","text":"It highlights the row when the user hovers over it"}],"explanation":"The --row-tint CSS custom property is set to the job's stage color (job.stageColor) via the backlogRowStyle function. This gives each row a subtle background tint that visually indicates which stage the job is in, even without reading the Stage column."},{"id":"bl8","text":"When does the Track Type field appear in the job dialog?","options":[{"id":"a","text":"It always appears in both create and edit modes"},{"id":"b","text":"It only appears in create mode — track type cannot be changed after creation","isCorrect":true},{"id":"c","text":"It only appears in edit mode — create mode auto-assigns a default track"},{"id":"d","text":"It appears as a read-only display field in edit mode"}],"explanation":"The Track Type select (data-testid: job-track-type) is only shown in create mode. Once a job is created, its track type is permanent and determines which kanban board it belongs to. In edit mode, the field is hidden entirely."},{"id":"bl9","text":"How does the Backlog handle deep linking to a specific job's detail?","options":[{"id":"a","text":"Job IDs are stored in localStorage and restored on page load"},{"id":"b","text":"The URL includes ?detail=job:{id} which triggers the detail dialog to auto-open on page load","isCorrect":true},{"id":"c","text":"Deep linking is not supported — you must click a row to see details"},{"id":"d","text":"The job ID is stored in a route segment like /backlog/jobs/123"}],"explanation":"When you click a row or card, the URL updates to include ?detail=job:{id} via the DetailDialogService. On page load, if this query param is present, the detail dialog opens automatically. This makes links shareable and bookmarkable, and supports browser back/forward navigation."},{"id":"bl10","text":"What icon is used for the Card View toggle button?","options":[{"id":"a","text":"grid_view"},{"id":"b","text":"dashboard"},{"id":"c","text":"view_module","isCorrect":true},{"id":"d","text":"apps"}],"explanation":"The Card View toggle uses the view_module Material icon. The Table View toggle uses view_list. Both are in the page header's view-toggle group. The active button gets the icon-btn--active class."},{"id":"bl11","text":"In card view, what triggers the 'On Hold' badge to appear on a job card?","options":[{"id":"a","text":"The job's priority is set to Urgent"},{"id":"b","text":"The job has been in the same stage for more than 7 days"},{"id":"c","text":"The job has one or more active holds (job.activeHolds.length > 0)","isCorrect":true},{"id":"d","text":"The job's assignee has not logged in recently"}],"explanation":"The 'On Hold' badge (a warning-colored chip) appears in the card header when job.activeHolds.length > 0. Holds are managed through the job detail dialog's status lifecycle features and indicate the job is blocked or paused."},{"id":"bl12","text":"What color represents a 'High' priority job's dot in the backlog?","options":[{"id":"a","text":"Red (#dc2626)"},{"id":"b","text":"Teal (#0d9488)"},{"id":"c","text":"Amber (#f59e0b)","isCorrect":true},{"id":"d","text":"Slate gray (#94a3b8)"}],"explanation":"Priority colors are: Low = #94a3b8 (slate gray), Normal = #0d9488 (teal), High = #f59e0b (amber), Urgent = #dc2626 (red). These colors are defined in the PRIORITY_COLORS constant and used for both the table dot and the card view dot."},{"id":"bl13","text":"What happens when you hover over a disabled Save button in the job creation dialog?","options":[{"id":"a","text":"Nothing — the button is grayed out with no additional feedback"},{"id":"b","text":"A tooltip says 'Please fill in all required fields'"},{"id":"c","text":"A validation popover appears listing which fields have errors (e.g., 'Title is required')","isCorrect":true},{"id":"d","text":"The invalid fields flash red to draw attention"}],"explanation":"The Save button uses the ValidationPopoverDirective ([appValidationPopover]). When the form is invalid and you hover over the disabled button, a popover appears with a bulleted list of validation violations, such as 'Title is required' or 'Track Type is required'. This is the standard QB Engineer form validation pattern — no inline mat-error messages."},{"id":"bl14","text":"How does the Track Type filter work in the Backlog?","options":[{"id":"a","text":"It hides all jobs except those whose job.trackTypeId matches the selected track"},{"id":"b","text":"It filters jobs by matching the job's current stage name against the selected track type's stage list","isCorrect":true},{"id":"c","text":"It groups the table rows by track type, collapsing non-selected tracks"},{"id":"d","text":"It navigates you to the Kanban Board for the selected track"}],"explanation":"The Track Type filter looks up the selected track's stages, builds a Set of stage names, and filters jobs to only those whose current stageName is in that set. This means if a job is in a stage that belongs to the selected track, it appears — the filter works through stage membership, not a direct trackTypeId on the job."},{"id":"bl15","text":"What data-testid would you use to locate the due date picker in the job creation dialog?","options":[{"id":"a","text":"data-testid=\"job-dueDate\""},{"id":"b","text":"data-testid=\"job-due-date\"","isCorrect":true},{"id":"c","text":"data-testid=\"backlog-due-date\""},{"id":"d","text":"data-testid=\"create-due-date\""}],"explanation":"The due date picker has data-testid=\"job-due-date\". The job dialog uses the naming convention data-testid=\"job-{field-name}\" with kebab-case field names: job-title, job-description, job-track-type, job-customer, job-assignee, job-priority, job-due-date, and job-save-btn."}]}"""
        });

        Log.Information("Seeded Backlog training modules");
    }
}
